using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: happy-path combinations via DataRow ---

    [TestMethod]
    [DataRow(10.00, 2, 0.10, 22.00, DisplayName = "Basic with 10% tax")]
    [DataRow(5.50, 4, 0.0, 22.00, DisplayName = "Zero tax")]
    [DataRow(0.00, 5, 0.25, 0.00, DisplayName = "Zero unit price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    [DataRow(100.00, 1, 1.0, 200.00, DisplayName = "Max tax rate (100%)")]
    [DataRow(7.25, 3, 0.08, 23.49, DisplayName = "Typical sales tax")]
    public void CalculateTotal_ValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    // --- CalculateTotal: invalid-input combinations via DynamicData ---

    [TestMethod]
    [DynamicData(nameof(CalculateTotal_InvalidInputData))]
    public void CalculateTotal_InvalidInputs_ThrowsArgumentOutOfRange(
        decimal unitPrice, int quantity, decimal taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal(unitPrice, quantity, taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    public static IEnumerable<(decimal unitPrice, int quantity, decimal taxRate, string expectedParam)>
        CalculateTotal_InvalidInputData =>
    [
        (-1m, 1, 0.1m, "unitPrice"),
        (10m, -1, 0.1m, "quantity"),
        (10m, 1, -0.01m, "taxRate"),
        (10m, 1, 1.01m, "taxRate"),
    ];

    // --- ApplyDiscount: multiple combinations via DynamicData ---

    [TestMethod]
    [DynamicData(nameof(ApplyDiscount_ValidData))]
    public void ApplyDiscount_ValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)>
        ApplyDiscount_ValidData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (0m, 50m, 0m),
    ];

    // --- ApplyDiscount: boundary violations ---

    [TestMethod]
    [DataRow(-0.01, DisplayName = "Below 0%")]
    [DataRow(100.01, DisplayName = "Above 100%")]
    public void ApplyDiscount_InvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));
    }

    // --- FormatPrice ---

    [TestMethod]
    [DataRow(9.99, "$", "$9.99")]
    [DataRow(1234.50, "€", "€1234.50")]
    [DataRow(0.00, "$", "$0.00")]
    public void FormatPrice_WithSymbol_ReturnsFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }

    [TestMethod]
    public void FormatPrice_DefaultSymbol_UsesDollarSign()
    {
        var result = _calculator.FormatPrice(5.00m);

        Assert.StartsWith("$", result);
        Assert.AreEqual("$5.00", result);
    }
}

